body:
for short names like "Struct" it's worse on multi-line, but for long names, especially across packages, it looks better.

If we want to really make clean code, we would render to a buffer as one-line and see how long it is and then (if too long) re-render as multi-line.  Not good ROI?

pkg/apis/core/v1/zz_generated.validations.go
```
func RegisterValidations(scheme *runtime.Scheme) error {    
    // type ReplicationController    
    scheme.AddValidationFunc(    
        (*corev1.ReplicationController)(nil),    
        func(ctx context.Context, op operation.Operation, obj, oldObj interface{}) field.ErrorList {    
            switch op.Request.SubresourcePath() {    
            case "/", "/scale", "/status":        
                return Validate_ReplicationController(    
                    ctx, op, nil, /* fldPath */    
                    obj.(*corev1.ReplicationController),    
                    safe.Cast[*corev1.ReplicationController](oldObj))    
            }    
            return field.ErrorList{    
                field.InternalError(nil, fmt.Errorf("no validation found for %T, subresource: %v", obj, op.Request.SubresourcePath())),    
            }    
        })    
    return nil    
}    
```

